package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.within;

import java.io.File;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicLong;

import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Unit tests for the predictive (GDSF-style) eviction and admission control of {@link LmdbCsrAdjacencyCache}: victims
 * are chosen by decayed popularity weighed against rebuild cost per byte, stale entries always evict first, cold builds
 * are refused while the budget is full of hotter entries, and the kill switch restores the exact second-chance clock.
 */
public class LmdbCsrPredictiveEvictionTest {

	@TempDir
	File dataDir;

	private TripleStore tripleStore;
	private AtomicBoolean storeTxnStarted;
	private LmdbCsrAdjacencyCache cache;
	private Map<String, String> previousProperties;
	private final AtomicLong fakeNanos = new AtomicLong(1_000_000_000L);

	@BeforeEach
	public void setUp() throws Exception {
		previousProperties = new HashMap<>();
		for (String property : new String[] { "rdf4j.lmdb.csrCache.minProbes", "rdf4j.lmdb.csrCache.maxBytes",
				"rdf4j.lmdb.csrCache.maxEntryBytes", "rdf4j.lmdb.csrCache.predictiveEviction.enabled",
				"rdf4j.lmdb.csrCache.evictionSampleSize", "rdf4j.lmdb.csrCache.scoreHalfLifeSeconds",
				"rdf4j.lmdb.csrCache.autoWarm.enabled", "rdf4j.lmdb.csrCache.autoWarm.minScore",
				"rdf4j.lmdb.csrCache.autoWarm.initialScore" }) {
			previousProperties.put(property, System.getProperty(property));
		}
		// no inline builds: every build in these tests goes through buildEagerly
		System.setProperty("rdf4j.lmdb.csrCache.minProbes", Integer.toString(Integer.MAX_VALUE));
		LmdbCsrAdjacencyCache.NANO_CLOCK = fakeNanos::get;
		tripleStore = new TestTripleStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		storeTxnStarted = new AtomicBoolean(false);
		cache = new LmdbCsrAdjacencyCache(tripleStore, storeTxnStarted);
		resetCounters();
	}

	@AfterEach
	public void tearDown() throws Exception {
		LmdbCsrAdjacencyCache.NANO_CLOCK = System::nanoTime;
		for (Map.Entry<String, String> entry : previousProperties.entrySet()) {
			if (entry.getValue() == null) {
				System.clearProperty(entry.getKey());
			} else {
				System.setProperty(entry.getKey(), entry.getValue());
			}
		}
		if (cache != null) {
			cache.close();
		}
		if (tripleStore != null) {
			tripleStore.close();
		}
	}

	private static void resetCounters() {
		LmdbCsrAdjacencyCache.BUILDS.set(0);
		LmdbCsrAdjacencyCache.BUILDS_DISCARDED.set(0);
		LmdbCsrAdjacencyCache.HITS.set(0);
		LmdbCsrAdjacencyCache.STALE_DROPS.set(0);
		LmdbCsrAdjacencyCache.EVICTIONS.set(0);
		LmdbCsrAdjacencyCache.REFUSALS.set(0);
		LmdbCsrAdjacencyCache.PREDICTIVE_EVICTIONS.set(0);
		LmdbCsrAdjacencyCache.ADMISSION_SKIPS.set(0);
		LmdbCsrAdjacencyCache.AUTO_WARM_BUILDS.set(0);
	}

	/**
	 * Stores {@code subjects * objectsPerSubject} pairs under {@code pred}; last object per subject is in context 7.
	 */
	private void loadPredicate(long pred, int subjects, int objectsPerSubject) throws Exception {
		tripleStore.startTransaction();
		for (long s = 0; s < subjects; s++) {
			long subj = 100 + s;
			for (long b = 0; b < objectsPerSubject; b++) {
				long context = b == objectsPerSubject - 1 ? 7 : 0;
				tripleStore.storeTriple(subj, pred, 100_000 + pred * 1_000 + subj * 10 + b, context, true);
			}
		}
		tripleStore.commit();
	}

	private void buildEagerly(long pred) throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			cache.buildEagerly(pred, LmdbCsrAdjacencyCache.BY_SUBJECT, true, txn);
		}
	}

	private void probe(long pred, int opens) throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			cache.recordProbes(pred, LmdbCsrAdjacencyCache.BY_SUBJECT, true, opens, txn);
		}
	}

	private void hit(long pred, int times) {
		for (int i = 0; i < times; i++) {
			assertThat(cache.lookup(pred, LmdbCsrAdjacencyCache.BY_SUBJECT, true)).isNotNull();
		}
	}

	private boolean resident(long pred) {
		return cache.lookup(pred, LmdbCsrAdjacencyCache.BY_SUBJECT, true) != null;
	}

	@Test
	public void evictsLowestScoreEntry() throws Exception {
		loadPredicate(10, 20, 3);
		loadPredicate(11, 20, 3);
		loadPredicate(12, 20, 3);

		long baseline = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		buildEagerly(10);
		long entryBytes = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get() - baseline;
		assertThat(entryBytes).isPositive();
		buildEagerly(11);
		System.setProperty("rdf4j.lmdb.csrCache.maxBytes", Long.toString(baseline + 2 * entryBytes));

		hit(10, 100);
		hit(11, 2);
		probe(12, 50);

		buildEagerly(12);

		assertThat(resident(11)).as("the coldest entry must be the predictive victim").isFalse();
		assertThat(resident(10)).isTrue();
		assertThat(resident(12)).isTrue();
		assertThat(LmdbCsrAdjacencyCache.PREDICTIVE_EVICTIONS.get()).isEqualTo(1L);
		assertThat(LmdbCsrAdjacencyCache.EVICTIONS.get()).isEqualTo(1L);
	}

	@Test
	public void decayDemotesFormerlyHotEntry() throws Exception {
		System.setProperty("rdf4j.lmdb.csrCache.scoreHalfLifeSeconds", "1");
		loadPredicate(10, 20, 3);
		loadPredicate(11, 20, 3);
		loadPredicate(12, 20, 3);

		long baseline = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		buildEagerly(10);
		long entryBytes = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get() - baseline;
		buildEagerly(11);
		System.setProperty("rdf4j.lmdb.csrCache.maxBytes", Long.toString(baseline + 2 * entryBytes));

		hit(10, 100);
		assertThat(cache.popularityScore(10, LmdbCsrAdjacencyCache.BY_SUBJECT, true))
				.isCloseTo(100.0, within(1e-9));

		// ten half-lives of silence: the formerly hot predicate decays to ~0.098
		fakeNanos.addAndGet(10L * 1_000_000_000L);
		assertThat(cache.popularityScore(10, LmdbCsrAdjacencyCache.BY_SUBJECT, true)).isLessThan(1.0);

		hit(11, 10);
		probe(12, 50);
		buildEagerly(12);

		assertThat(resident(10)).as("a decayed formerly-hot entry must lose to a recently-used one").isFalse();
		assertThat(resident(11)).isTrue();
		assertThat(resident(12)).isTrue();
		assertThat(LmdbCsrAdjacencyCache.PREDICTIVE_EVICTIONS.get()).isEqualTo(1L);
	}

	@Test
	public void costAwareTieBreak() throws Exception {
		// pred 20: 4 pairs — a trivial rebuild, so evicting it is low-regret; pred 21: 400 pairs — two full sweeps to
		// reload, so at equal popularity it must be kept
		loadPredicate(20, 2, 2);
		loadPredicate(21, 40, 10);
		loadPredicate(22, 2, 2);

		long baseline = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		buildEagerly(20);
		buildEagerly(21);
		long bothBytes = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get() - baseline;
		System.setProperty("rdf4j.lmdb.csrCache.maxBytes", Long.toString(baseline + bothBytes));

		hit(20, 10);
		hit(21, 10);
		probe(22, 50);
		buildEagerly(22);

		assertThat(resident(20)).as("at equal scores the cheap-to-rebuild entry must be the victim").isFalse();
		assertThat(resident(21)).isTrue();
		assertThat(resident(22)).isTrue();
		assertThat(LmdbCsrAdjacencyCache.PREDICTIVE_EVICTIONS.get()).isEqualTo(1L);
	}

	@Test
	public void staleEntriesStillEvictedFirst() throws Exception {
		loadPredicate(10, 20, 3);
		loadPredicate(11, 20, 3);
		loadPredicate(12, 20, 3);

		long baseline = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		buildEagerly(10);
		long entryBytes = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get() - baseline;
		hit(10, 100);

		// a committed write makes the hot entry stale; no lookups on pred 10 after this
		tripleStore.startTransaction();
		tripleStore.storeTriple(500, 99, 9_999, 0, true);
		tripleStore.commit();

		buildEagerly(11);
		hit(11, 100);
		System.setProperty("rdf4j.lmdb.csrCache.maxBytes", Long.toString(baseline + 2 * entryBytes));

		probe(12, 50);
		buildEagerly(12);

		assertThat(resident(11)).isTrue();
		assertThat(resident(12)).isTrue();
		assertThat(LmdbCsrAdjacencyCache.STALE_DROPS.get())
				.as("staleness must beat hotness in victim selection")
				.isEqualTo(1L);
		assertThat(LmdbCsrAdjacencyCache.PREDICTIVE_EVICTIONS.get()).isZero();
		assertThat(LmdbCsrAdjacencyCache.EVICTIONS.get()).isZero();
	}

	@Test
	public void admissionSkipsColdBuildWhenBudgetFull() throws Exception {
		loadPredicate(10, 20, 3);
		loadPredicate(11, 20, 3);
		loadPredicate(12, 20, 3);

		long baseline = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		buildEagerly(10);
		long entryBytes = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get() - baseline;
		buildEagerly(11);
		System.setProperty("rdf4j.lmdb.csrCache.maxBytes", Long.toString(baseline + 2 * entryBytes));
		hit(10, 100);
		hit(11, 100);

		for (int i = 0; i < 3; i++) {
			buildEagerly(12);
		}

		assertThat(resident(12)).as("a cold build must not displace hotter residents").isFalse();
		assertThat(LmdbCsrAdjacencyCache.ADMISSION_SKIPS.get()).isEqualTo(3L);
		assertThat(LmdbCsrAdjacencyCache.EVICTIONS.get()).isZero();
		assertThat(LmdbCsrAdjacencyCache.BUILDS_DISCARDED.get())
				.as("an admission skip is not a build failure and must not feed the backoff")
				.isZero();
		assertThat(cache.entryCount()).isEqualTo(2);

		// once the candidate outgrows the coldest resident it must be admitted despite the earlier skips
		probe(12, 200);
		buildEagerly(12);
		assertThat(resident(12)).isTrue();
		assertThat(LmdbCsrAdjacencyCache.EVICTIONS.get()).isEqualTo(1L);
	}

	@Test
	public void killSwitchRestoresSecondChanceClock() throws Exception {
		System.setProperty("rdf4j.lmdb.csrCache.predictiveEviction.enabled", "false");
		loadPredicate(10, 20, 3);
		loadPredicate(11, 20, 3);
		loadPredicate(12, 20, 3);

		long baseline = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		buildEagerly(10);
		long entryBytes = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get() - baseline;
		buildEagerly(11);
		System.setProperty("rdf4j.lmdb.csrCache.maxBytes", Long.toString(baseline + 2 * entryBytes));

		hit(10, 100);
		buildEagerly(12);

		// second-chance clock: both referenced, hand clears 10 then 11, comes back and evicts 10 despite its heat
		assertThat(resident(10)).as("the kill switch must restore hand-order second-chance eviction").isFalse();
		assertThat(resident(11)).isTrue();
		assertThat(resident(12)).isTrue();
		assertThat(LmdbCsrAdjacencyCache.EVICTIONS.get()).isEqualTo(1L);
		assertThat(LmdbCsrAdjacencyCache.PREDICTIVE_EVICTIONS.get()).isZero();
		assertThat(LmdbCsrAdjacencyCache.ADMISSION_SKIPS.get()).isZero();
	}

	private static final class TestTripleStore extends TripleStore {
		TestTripleStore(File dir, LmdbStoreConfig config) throws Exception {
			super(dir, config, null);
		}
	}
}
